import React, { useState, useCallback, useRef } from 'react';
import UploadComponent from './components/UploadComponent';
import CompressionControls from './components/CompressionControls';
import ResultPreview from './components/ResultPreview';
import { compressImageToTargetSize, dataUrlToFile } from './utils/compression';
import './App.css';

function App() {
  const [originalImage, setOriginalImage] = useState(null);
  const [compressedImage, setCompressedImage] = useState(null);
  const [originalSize, setOriginalSize] = useState(0);
  const [compressedSize, setCompressedSize] = useState(0);
  const [isDragging, setIsDragging] = useState(false);
  const [isCompressing, setIsCompressing] = useState(false);
  const [error, setError] = useState('');
  const [compressionQuality, setCompressionQuality] = useState(0.8);
  const [targetSizeKB, setTargetSizeKB] = useState('');
  const [fileName, setFileName] = useState('');
  const [originalFileName, setOriginalFileName] = useState('');
  const [compressionInfo, setCompressionInfo] = useState(null);
  const fileInputRef = useRef(null);

  const formatFileSize = (bytes) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const calculateCompressionPercentage = () => {
    if (originalSize === 0) return 0;
    return ((originalSize - compressedSize) / originalSize * 100).toFixed(1);
  };

  const validateFile = (file) => {
    const validTypes = ['image/jpeg', 'image/jpg', 'image/png'];
    if (!validTypes.includes(file.type)) {
      setError('Please upload a JPG or PNG image file.');
      return false;
    }

    const maxSize = 10 * 1024 * 1024; // 10MB
    if (file.size > maxSize) {
      setError('File size must be less than 10MB.');
      return false;
    }

    return true;
  };

  const handleFile = (file) => {
    setError('');
    if (!validateFile(file)) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      setOriginalImage(e.target.result);
      setOriginalSize(file.size);
      setCompressedImage(null);
      setCompressedSize(0);
    };
    reader.readAsDataURL(file);
  };

  const handleFileInput = (e) => {
    const file = e.target.files[0];
    if (file) {
      handleFile(file);
    }
  };

  const handleDrop = useCallback((e) => {
    e.preventDefault();
    setIsDragging(false);

    const file = e.dataTransfer.files[0];
    if (file) {
      handleFile(file);
    }
  }, []);

  const handleDragOver = useCallback((e) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const compressImage = async () => {
    if (!originalImage) return;

    setIsCompressing(true);
    setError('');

    try {
      const options = {
        maxSizeMB: 1,
        maxWidthOrHeight: 1920,
        useWebWorker: true,
        quality: compressionQuality,
      };

      // Convert data URL to File
      const response = await fetch(originalImage);
      const blob = await response.blob();
      const file = new File([blob], 'image.jpg', { type: blob.type });

      const compressedFile = await imageCompression(file, options);

      // Convert compressed file to data URL
      const compressedDataUrl = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result);
        reader.readAsDataURL(compressedFile);
      });

      setCompressedImage(compressedDataUrl);
      setCompressedSize(compressedFile.size);
    } catch (err) {
      setError('Failed to compress image. Please try again.');
      console.error('Compression error:', err);
    } finally {
      setIsCompressing(false);
    }
  };

  const downloadImage = () => {
    if (!compressedImage) return;

    const link = document.createElement('a');
    link.href = compressedImage;
    link.download = `compressed-image-${Date.now()}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const reset = () => {
    setOriginalImage(null);
    setCompressedImage(null);
    setOriginalSize(0);
    setCompressedSize(0);
    setError('');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <div className="container mx-auto px-4 py-8 max-w-4xl">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-gray-800 mb-2">Image Compressor Tool</h1>
          <p className="text-gray-600">Compress your images online for free. Fast, secure, and works entirely in your browser.</p>
        </header>

        <main className="card p-6 md:p-8">
          {!originalImage ? (
            <div className="space-y-6">
              <div
                className={`drop-zone ${isDragging ? 'drag-over' : ''}`}
                onDrop={handleDrop}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onClick={() => fileInputRef.current?.click()}
              >
                <div className="space-y-4">
                  <div className="mx-auto w-16 h-16 bg-primary-100 rounded-full flex items-center justify-center">
                    <svg className="w-8 h-8 text-primary-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                    </svg>
                  </div>
                  <div>
                    <p className="text-lg font-medium text-gray-700">Drop your image here</p>
                    <p className="text-sm text-gray-500 mt-1">or click to browse</p>
                  </div>
                  <p className="text-xs text-gray-400">Supports: JPG, PNG (Max 10MB)</p>
                </div>
              </div>

              <input
                ref={fileInputRef}
                type="file"
                accept="image/jpeg,image/jpg,image/png"
                onChange={handleFileInput}
                className="hidden"
              />
            </div>
          ) : (
            <div className="space-y-6">
              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <h3 className="font-semibold text-gray-700">Original Image</h3>
                  <div className="relative group">
                    <img
                      src={originalImage}
                      alt="Original"
                      className="w-full h-48 object-contain bg-gray-50 rounded-lg border border-gray-200"
                    />
                    <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
                      {formatFileSize(originalSize)}
                    </div>
                  </div>
                </div>

                {compressedImage && (
                  <div className="space-y-3">
                    <h3 className="font-semibold text-gray-700">Compressed Image</h3>
                    <div className="relative group">
                      <img
                        src={compressedImage}
                        alt="Compressed"
                        className="w-full h-48 object-contain bg-gray-50 rounded-lg border border-gray-200"
                      />
                      <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
                        {formatFileSize(compressedSize)}
                      </div>
                    </div>
                  </div>
                )}
              </div>

              {compressedImage && (
                <div className="bg-green-50 border border-green-200 rounded-lg p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-green-800 font-medium">Compression Successful!</p>
                      <p className="text-green-600 text-sm mt-1">
                        Reduced size by {calculateCompressionPercentage()}%
                      </p>
                    </div>
                    <div className="text-right">
                      <p className="text-2xl font-bold text-green-700">{calculateCompressionPercentage()}%</p>
                      <p className="text-xs text-green-600">size reduction</p>
                    </div>
                  </div>
                </div>
              )}

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Compression Quality: {Math.round(compressionQuality * 100)}%
                  </label>
                  <input
                    type="range"
                    min="0.1"
                    max="1"
                    step="0.1"
                    value={compressionQuality}
                    onChange={(e) => setCompressionQuality(parseFloat(e.target.value))}
                    className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-primary-600"
                  />
                  <div className="flex justify-between text-xs text-gray-500 mt-1">
                    <span>Lower size</span>
                    <span>Higher quality</span>
                  </div>
                </div>

                <div className="flex flex-wrap gap-3">
                  {!compressedImage && (
                    <button
                      onClick={compressImage}
                      disabled={isCompressing}
                      className="btn-primary disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      {isCompressing ? (
                        <span className="flex items-center">
                          <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                          </svg>
                          Compressing...
                        </span>
                      ) : 'Compress Image'}
                    </button>
                  )}

                  {compressedImage && (
                    <button
                      onClick={downloadImage}
                      className="btn-primary"
                    >
                      Download Compressed Image
                    </button>
                  )}

                  <button
                    onClick={reset}
                    className="btn-secondary"
                  >
                    Upload New Image
                  </button>
                </div>
              </div>
            </div>
          )}

          {error && (
            <div className="mt-4 bg-red-50 border border-red-200 rounded-lg p-4">
              <p className="text-red-800 text-sm">{error}</p>
            </div>
          )}
        </main>

        <footer className="text-center mt-8 text-gray-600 text-sm">
          <p>Your images are processed locally in your browser. No data is sent to any server.</p>
        </footer>
      </div>
    </div>
  );
}

export default App;
